mapper.select:
select r.*, e.name as examName, s.name as studentName
from `exam_recording` r
left join `exam` e on r.exam_id = e.id
left join `student` s on r.student_id = s.id

     and r.exam_id = #{examId}
     and r.student_id = #{studentId}
     and r.status = #{status}

order by r.id desc

mapper.update:
update `exam_recording`
file_url = #{fileUrl}, file_size = #{fileSize}, duration = #{duration}, switch_count = #{switchCount}, status = #{status},
where id = #{id}
